size(6cm);
defaultpen(linewidth(.7pt)+fontsize(8pt));
dotfactor=4;

pair A=(8,0), B=(7,0), C=7*dir(60), D=9*dir(60), Ep=(13,0)+9*dir(120), F=(13,0)+5*dir(120), G=(13,0), H=(0,0), J=13*dir(60);

pair[] dots = {A, B, C, D, Ep, F};

dot(dots);

draw(A--B--C--D--Ep--F--cycle);

draw(B--H--C,dashed);
draw(D--J--Ep,dashed);
draw(F--G--A,dashed);

label("$A$",A,S);
label("$B$",B,S);
label("$C$",C,NW);
label("$D$",D,NW);
label("$E$",Ep,NE);
label("$F$",F,NE);
label("$G$",G,SE);
label("$H$",H,SW);
label("$J$",J,N);

label("$1$",(A+B)/2,N);
label("$7$",(B+C)/2,NE);
label("$2$",(C+D)/2,SE);
label("$4$",(D+Ep)/2,S);
[/asy]

